prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?elem ?elemName WHERE {
  ?model tai:normalizedId "1ad939eef40c461dafae27f75a0586d3" .
  ?choreo a bboExt:Choreography .
  ?elem tai:belongsTo ?choreo .
  ?elem bbo:name ?elemName .
  {
    SELECT DISTINCT ?elem WHERE {
      ?s ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?elem .
      FILTER(?s = ?elem)
    } LIMIT 1
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?start ?startName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "1ad939eef40c461dafae27f75a0586d3" ;
         tai:belongsTo ?org .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?start tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  # cyclic behaviour: start node can reach itself via at least one outgoing traversal
  ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?start .
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT (COUNT(*) AS ?seqFlowCount) ?choreo WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "1ad939eef40c461dafae27f75a0586d3" ;
         tai:belongsTo ?org .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .
  ?edge a bbo:SequenceFlow ;
        tai:belongsTo ?choreo .
}
GROUP BY ?choreo
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER(STR(?origId) = "1ad939eef40c461dafae27f75a0586d3" || STR(?normId) = "1ad939eef40c461dafae27f75a0586d3")
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName (COUNT(DISTINCT ?edge) AS ?seqFlowCount) WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1ad939eef40c461dafae27f75a0586d3" ;
         tai:belongsTo ?org .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
  OPTIONAL {
    ?edge a bbo:SequenceFlow ;
          tai:belongsTo ?choreo .
  }
}
GROUP BY ?choreo ?choreoName
ORDER BY DESC(?seqFlowCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?defs ?defsName ?typeName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1ad939eef40c461dafae27f75a0586d3" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  OPTIONAL { ?defs bbo:name ?defsName . }
  BIND( "definitions" AS ?typeName )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?cont ?contType ?contName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1ad939eef40c461dafae27f75a0586d3" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .

  ?cont a ?contType ;
        tai:belongsTo ?defs .
  FILTER(?contType IN (bboExt:Choreography, bboExt:Collaboration))

  OPTIONAL { ?cont bbo:name ?contName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?edge) AS ?sequenceFlowCount) WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1ad939eef40c461dafae27f75a0586d3" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  ?edge a bbo:SequenceFlow ;
        tai:belongsTo ?choreo .
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?cycleNode ?cycleNodeName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1ad939eef40c461dafae27f75a0586d3" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?cycleNode tai:belongsTo ?choreo .
  OPTIONAL { ?cycleNode bbo:name ?cycleNodeName . }

  ?cycleNode ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?cycleNode .
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?node ?nodeName ?type ?id WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1ad939eef40c461dafae27f75a0586d3" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  ?node tai:belongsTo ?choreo .
  OPTIONAL { ?node bbo:name ?nodeName . }
  OPTIONAL { ?node bbo:id ?id . }
  ?node a ?type .

  ?node ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?node .
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?srcName ?srcNode ?dstNode ?dstName ?flowId WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1ad939eef40c461dafae27f75a0586d3" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  ?srcNode tai:belongsTo ?choreo .
  OPTIONAL { ?srcNode bbo:name ?srcName . }

  ?flow a bbo:SequenceFlow ;
        bbo:has_sourceRef ?srcNode ;
        bbo:has_targetRef ?dstNode ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?flow bbo:id ?flowId . }
  OPTIONAL { ?dstNode bbo:name ?dstName . }

  # restrict to the previously found cyclic nodes (self-reachable)
  { ?srcNode ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?srcNode . }
}
LIMIT 25
